67	// beadRoutingDecisionsFromStore reads kind:routing evidence events from all beads
68	// in the store at workDir/.ddx and returns them as recentRoutingDecision entries.
69	func beadRoutingDecisionsFromStore(workDir string) []recentRoutingDecision {
70		store := bead.NewStore(filepath.Join(workDir, ".ddx"))
71		beads, err := store.ReadAll()
72		if err != nil {
73			return nil
74		}
75		var out []recentRoutingDecision
76		for _, b := range beads {
77			events := routingEventsFromBeadExtra(b.Extra)
78			for _, e := range events {
79				d := recentRoutingDecision{
80					ObservedAt: e.CreatedAt,
81					Source:     "bead-evidence",
82					BeadID:     b.ID,
83				}
84				if e.Body != "" {
85					var body struct {
86						ResolvedProvider string `json:"resolved_provider"`
87						ResolvedModel    string `json:"resolved_model"`
88						RouteReason      string `json:"route_reason"`
89					}
90					if jsonErr := json.Unmarshal([]byte(e.Body), &body); jsonErr == nil {
91						d.Provider = body.ResolvedProvider
92						d.Model = body.ResolvedModel
93						d.RouteReason = body.RouteReason
94					}
95				}
96				out = append(out, d)
97			}
98		}
99		return out
100	}
101	
102	// routingEventsFromBeadExtra extracts kind:routing BeadEvents from a bead's
103	// Extra map without an additional store read. Extra["events"] is stored as
104	// []any of map[string]any when loaded from JSONL.
105	func routingEventsFromBeadExtra(extra map[string]any) []bead.BeadEvent {
106		if extra == nil {
107			return nil
108		}
109		raw, ok := extra["events"]
110		if !ok {
111			return nil
112		}
113		items, ok := raw.([]any)
114		if !ok {
115			return nil
116		}
117		var out []bead.BeadEvent
118		for _, item := range items {
119			m, ok := item.(map[string]any)
120			if !ok {
121				continue
122			}
123			k, _ := m["kind"].(string)
124			if k != "routing" {
125				continue
126			}
127			e := bead.BeadEvent{Kind: k}
128			if v, ok := m["summary"].(string); ok {
129				e.Summary = v
130			}
131			if v, ok := m["body"].(string); ok {
132				e.Body = v
133			}
134			if v, ok := m["actor"].(string); ok {
135				e.Actor = v
136			}
137			if v, ok := m["source"].(string); ok {
138				e.Source = v
139			}
140			if v, ok := m["created_at"].(string); ok {
141				if t, err := time.Parse(time.RFC3339, v); err == nil {
142					e.CreatedAt = t
143				}
144			}
145			out = append(out, e)
146		}
147		return out
148	}
