115	// TestPassthroughEnvelope_InvariantUnderPowerEscalation (AC3): bumping MinPower
116	// does not mutate harness/provider/model in the passthrough.
117	func TestPassthroughEnvelope_InvariantUnderPowerEscalation(t *testing.T) {
118		rcfg := resolvedWithPassthrough("claude", "anthropic", "claude-3-5-sonnet", 0, 0)
119		pt := rcfg.Passthrough()
120	
121		// Simulate retry escalation: produce a new ResolvedConfig with higher MinPower
122		// but the same harness/provider/model. The passthrough must stay the same.
123		escalated := resolvedWithPassthrough("claude", "anthropic", "claude-3-5-sonnet", 50, 100)
124		ptEscalated := escalated.Passthrough()
125	
126		if ptEscalated.Harness != pt.Harness {
127			t.Errorf("Harness changed under escalation: got %q, want %q", ptEscalated.Harness, pt.Harness)
128		}
129		if ptEscalated.Provider != pt.Provider {
130			t.Errorf("Provider changed under escalation: got %q, want %q", ptEscalated.Provider, pt.Provider)
131		}
132		if ptEscalated.Model != pt.Model {
133			t.Errorf("Model changed under escalation: got %q, want %q", ptEscalated.Model, pt.Model)
134		}
135	
136		// MaxPower must be preserved too.
137		if escalated.MaxPower() != 100 {
138			t.Errorf("MaxPower should be 100 after escalation, got %d", escalated.MaxPower())
139		}
140		if escalated.MinPower() != 50 {
141			t.Errorf("MinPower should be 50 after escalation, got %d", escalated.MinPower())
142		}
143	}
