		"--model", "claude-opus-4-7",
		"--min-power", "40",
		"--max-power", "90",
	)
	// Command may fail (no real provider configured) but Execute must be called.

	stub.mu.Lock()
	executeCalled := stub.executeCalled
	lastReq := stub.lastReq
	stub.mu.Unlock()

	if !executeCalled {
		t.Skip("Execute not called — bead may not have been claimed")
	}
	// Verify ResolveRoute wasn't called (stub.Execute succeeded, so no error from stub.ResolveRoute).
	assert.Equal(t, "claude", lastReq.Harness, "Harness passthrough must reach Execute")
	assert.Equal(t, "claude-opus-4-7", lastReq.Model, "Model passthrough must reach Execute")
	assert.Equal(t, 40, lastReq.MinPower, "MinPower must reach Execute unchanged")
	assert.Equal(t, 90, lastReq.MaxPower, "MaxPower must reach Execute unchanged")
