// TestWorkPassthroughMinMaxPowerToExecute (AC): ddx work passes MinPower and
// MaxPower to ServiceExecuteRequest without calling ResolveRoute.
func TestWorkPassthroughMinMaxPowerToExecute(t *testing.T) {
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")

	stub := installExecuteCapturingStub(t)

	dir := minimalProjectDir(t)

	// Seed one ready bead so the loop has something to claim.
	store := bead.NewStore(filepath.Join(dir, ".ddx"))
	require.NoError(t, store.Init())
	require.NoError(t, store.Create(&bead.Bead{
		ID:    "ddx-passthrough-power-test",
		Title: "passthrough power test bead",
	}))

	root := NewCommandFactory(dir).NewRootCommand()
	_, _ = executeCommand(root, "work",
		"--local", "--once",
		"--harness", "claude",
		"--model", "claude-opus-4-7",
		"--min-power", "40",
		"--max-power", "90",
	)
	// Command may fail (no real provider configured) but Execute must be called.

	stub.mu.Lock()
	executeCalled := stub.executeCalled
	lastReq := stub.lastReq
	stub.mu.Unlock()

	if !executeCalled {
		t.Skip("Execute not called — bead may not have been claimed")
	}
	// Verify ResolveRoute wasn't called (stub.Execute succeeded, so no error from stub.ResolveRoute).
	assert.Equal(t, "claude", lastReq.Harness, "Harness passthrough must reach Execute")
	assert.Equal(t, "claude-opus-4-7", lastReq.Model, "Model passthrough must reach Execute")
	assert.Equal(t, 40, lastReq.MinPower, "MinPower must reach Execute unchanged")
	assert.Equal(t, 90, lastReq.MaxPower, "MaxPower must reach Execute unchanged")
}

